const supabase = {
  // ── AUTH ──────────────────────────────────────────────────────────────────
  async signUp(email, password, name) {
    try {
      const res = await fetch(`${SUPABASE_URL}/auth/v1/signup`, {
        method:"POST",
        headers:{ "Content-Type":"application/json", "apikey":SUPABASE_ANON_KEY },
        body: JSON.stringify({ email, password, data:{ name } })
      });
      const data = await res.json();
      if (!res.ok) return { error: data.error_description || data.msg || "Sign up failed" };
      return { user:{ id:data.user?.id, email:data.user?.email, name, token:data.access_token } };
    } catch(e) { return { error:"Connection error. Check your internet." }; }
  },

  async signIn(email, password) {
    try {
      const res = await fetch(`${SUPABASE_URL}/auth/v1/token?grant_type=password`, {
        method:"POST",
        headers:{ "Content-Type":"application/json", "apikey":SUPABASE_ANON_KEY },
        body: JSON.stringify({ email, password })
      });
      const data = await res.json();
      if (!res.ok) return { error: data.error_description || "Invalid email or password" };
      return { user:{ id:data.user?.id, email:data.user?.email, name:data.user?.user_metadata?.name || email, token:data.access_token } };
    } catch(e) { return { error:"Connection error. Check your internet." }; }
  },

  async signOut(token) {
    try {
      await fetch(`${SUPABASE_URL}/auth/v1/logout`, {
        method:"POST",
        headers:{ "apikey":SUPABASE_ANON_KEY, "Authorization":`Bearer ${token}` }
      });
    } catch(e) {}
  },

  async resetPassword(email) {
    try {
      await fetch(`${SUPABASE_URL}/auth/v1/recover`, {
        method:"POST",
        headers:{ "Content-Type":"application/json", "apikey":SUPABASE_ANON_KEY },
        body: JSON.stringify({ email })
      });
      return { success:true };
    } catch(e) { return { error:"Could not send reset email." }; }
  },

  // ── DATABASE ───────────────────────────────────────────────────────────────
  async saveProgress(userId, token, progressData) {
    try {
      const res = await fetch(`${SUPABASE_URL}/rest/v1/user_progress`, {
        method:"POST",
        headers:{
          "Content-Type":"application/json",
          "apikey":SUPABASE_ANON_KEY,
          "Authorization":`Bearer ${token}`,
          "Prefer":"resolution=merge-duplicates"
        },
        body: JSON.stringify({ user_id:userId, progress:progressData, updated_at:new Date().toISOString() })
      });
      return res.ok;
    } catch(e) { return false; }
  },

  async loadProgress(userId, token) {
    try {
      const res = await fetch(`${SUPABASE_URL}/rest/v1/user_progress?user_id=eq.${userId}&select=progress`, {
        headers:{ "apikey":SUPABASE_ANON_KEY, "Authorization":`Bearer ${token}` }
      });
      const data = await res.json();
      return data?.[0]?.progress || null;
    } catch(e) { return null; }
  },

  // ── DOCUMENT STORAGE ───────────────────────────────────────────────────────
  async uploadDocument(userId, token, file, fileName) {
    try {
      const path = `${userId}/${Date.now()}_${fileName}`;
      const res = await fetch(`${SUPABASE_URL}/storage/v1/object/documents/${path}`, {
        method:"POST",
        headers:{
          "apikey":SUPABASE_ANON_KEY,
          "Authorization":`Bearer ${token}`,
          "Content-Type": file.type || "application/octet-stream"
        },
        body: file
      });
      if (!res.ok) return { error:"Upload failed" };
      return { path, url:`${SUPABASE_URL}/storage/v1/object/public/documents/${path}` };
    } catch(e) { return { error:"Upload error. Check connection." }; }
  },

  async listDocuments(userId, token) {
    try {
      const res = await fetch(`${SUPABASE_URL}/rest/v1/user_documents?user_id=eq.${userId}&order=created_at.desc`, {
        headers:{ "apikey":SUPABASE_ANON_KEY, "Authorization":`Bearer ${token}` }
      });
      const data = await res.json();
      return data || [];
    } catch(e) { return []; }
  },

  async saveDocumentRecord(userId, token, doc) {
    try {
      const res = await fetch(`${SUPABASE_URL}/rest/v1/user_documents`, {
        method:"POST",
        headers:{
          "Content-Type":"application/json",
          "apikey":SUPABASE_ANON_KEY,
          "Authorization":`Bearer ${token}`
        },
        body: JSON.stringify({ user_id:userId, ...doc, created_at:new Date().toISOString() })
      });
      return res.ok;
    } catch(e) { return false; }
  },

  async deleteDocument(docId, token) {
    try {
      const res = await fetch(`${SUPABASE_URL}/rest/v1/user_documents?id=eq.${docId}`, {
        method:"DELETE",
        headers:{ "apikey":SUPABASE_ANON_KEY, "Authorization":`Bearer ${token}` }
      });
      return res.ok;
    } catch(e) { return false; }
  },
};
