function AuthScreen({ onAuth, onGuest }) {
  const [mode, setMode] = useState("signin");
  const [email, setEmail] = useState("");
  const [password, setPassword] = useState("");
  const [name, setName] = useState("");
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState("");
  const [success, setSuccess] = useState("");
  const [showPassword, setShowPassword] = useState(false);
  const [showTerms, setShowTerms] = useState(false);
  const [showPrivacy, setShowPrivacy] = useState(false);
  const [showDisclaimer, setShowDisclaimer] = useState(false);
  const [resetSent, setResetSent] = useState(false);

  const handleAuth = async () => {
    if (!email.trim() || !password.trim()) { setError("Please enter your email and password."); return; }
    if (mode === "signup" && !name.trim()) { setError("Please enter your name."); return; }
    if (password.length < 6) { setError("Password must be at least 6 characters."); return; }
    setLoading(true); setError(""); setSuccess("");
    try {
      const result = mode === "signup"
        ? await supabase.signUp(email.trim(), password, name.trim())
        : await supabase.signIn(email.trim(), password);
      if (result.error) setError(result.error);
      else {
        if (mode === "signup") setSuccess("Account created! Check your email to verify your account, then sign in.");
        else onAuth(result.user);
      }
    } catch(e) { setError("Connection error. Check your internet and try again."); }
    setLoading(false);
  };

  const handleReset = async () => {
    if (!email.trim()) { setError("Enter your email address to reset your password."); return; }
    setLoading(true); setError("");
    const result = await supabase.resetPassword(email.trim());
    setLoading(false);
    if (result.error) setError(result.error);
    else { setResetSent(true); setSuccess("Password reset email sent. Check your inbox."); }
  };

  if (showTerms) return <TermsScreen go={()=>setShowTerms(false)} />;
  if (showPrivacy) return <PrivacyScreen go={()=>setShowPrivacy(false)} />;
  if (showDisclaimer) return <DisclaimerScreen go={()=>setShowDisclaimer(false)} />;

  return (
    <div style={{ background:C.bg, minHeight:"100vh", display:"flex", flexDirection:"column", alignItems:"center", justifyContent:"center", padding:24 }}>
      {/* Logo */}
      <div style={{ marginBottom:28, textAlign:"center" }}>
        <img src={LOGO_IMAGE} alt="StreetSmart" style={{ width:72, height:54, objectFit:"cover", objectPosition:"50% 72%", borderRadius:10, marginBottom:12 }} />
        <div style={{ fontSize:22, fontWeight:700, letterSpacing:2, color:"#FFFFFF" }}>STREET <span style={{ color:C.amber }}>SMART</span></div>
        <div style={{ color:C.gray2, fontSize:11, fontFamily:"Barlow,sans-serif", letterSpacing:1, marginTop:4 }}>FOR TRUCKERS</div>
      </div>

      {/* Tab switcher */}
      <div style={{ display:"flex", background:C.bg3, borderRadius:12, padding:4, marginBottom:20, width:"100%", maxWidth:340 }}>
        {[{id:"signin",label:"Sign In"},{id:"signup",label:"Create Account"}].map(t=>(
          <button key={t.id} onClick={()=>{ setMode(t.id); setError(""); setSuccess(""); }}
            style={{ flex:1, padding:"10px 0", background:mode===t.id?C.amber:"transparent", border:"none", borderRadius:10, color:mode===t.id?"#000":C.gray2, fontSize:13, fontWeight:700, fontFamily:"Oswald,sans-serif", letterSpacing:1, cursor:"pointer" }}>
            {t.label}
          </button>
        ))}
      </div>

      {/* Form */}
      <div style={{ width:"100%", maxWidth:340 }}>
        {mode === "signup" && (
          <div style={{ marginBottom:12 }}>
            <div style={{ color:C.gray2, fontSize:10, fontFamily:"Barlow,sans-serif", fontWeight:700, letterSpacing:1, marginBottom:6 }}>YOUR NAME</div>
            <input value={name} onChange={e=>setName(e.target.value)} placeholder="First and last name"
              style={{ width:"100%", boxSizing:"border-box", background:C.bg3, border:"1px solid "+C.border, borderRadius:10, padding:"13px 16px", color:C.offWhite, fontSize:14, fontFamily:"Barlow,sans-serif", outline:"none" }} />
          </div>
        )}

        <div style={{ marginBottom:12 }}>
          <div style={{ color:C.gray2, fontSize:10, fontFamily:"Barlow,sans-serif", fontWeight:700, letterSpacing:1, marginBottom:6 }}>EMAIL ADDRESS</div>
          <input value={email} onChange={e=>setEmail(e.target.value)} placeholder="your@email.com" type="email" autoCapitalize="none"
            style={{ width:"100%", boxSizing:"border-box", background:C.bg3, border:"1px solid "+C.border, borderRadius:10, padding:"13px 16px", color:C.offWhite, fontSize:14, fontFamily:"Barlow,sans-serif", outline:"none" }} />
        </div>

        <div style={{ marginBottom:6 }}>
          <div style={{ color:C.gray2, fontSize:10, fontFamily:"Barlow,sans-serif", fontWeight:700, letterSpacing:1, marginBottom:6 }}>PASSWORD</div>
          <div style={{ position:"relative" }}>
            <input value={password} onChange={e=>setPassword(e.target.value)} placeholder={mode==="signup"?"At least 6 characters":"Your password"} type={showPassword?"text":"password"}
              style={{ width:"100%", boxSizing:"border-box", background:C.bg3, border:"1px solid "+C.border, borderRadius:10, padding:"13px 44px 13px 16px", color:C.offWhite, fontSize:14, fontFamily:"Barlow,sans-serif", outline:"none" }} />
            <button onClick={()=>setShowPassword(!showPassword)}
              style={{ position:"absolute", right:12, top:"50%", transform:"translateY(-50%)", background:"none", border:"none", color:C.gray2, cursor:"pointer", fontSize:16 }}>
              {showPassword?"🙈":"👁️"}
            </button>
          </div>
        </div>

        {mode === "signin" && !resetSent && (
          <button onClick={handleReset} style={{ background:"none", border:"none", color:C.amber, fontSize:11, fontFamily:"Barlow,sans-serif", cursor:"pointer", padding:"4px 0", marginBottom:8 }}>
            Forgot your password?
          </button>
        )}

        {error && (
          <div style={{ background:"#EF535020", border:"1px solid #EF535050", borderRadius:10, padding:"10px 14px", marginBottom:12, color:"#EF5350", fontSize:12, fontFamily:"Barlow,sans-serif" }}>
            {error}
          </div>
        )}
        {success && (
          <div style={{ background:"#10B98120", border:"1px solid #10B98150", borderRadius:10, padding:"10px 14px", marginBottom:12, color:"#10B981", fontSize:12, fontFamily:"Barlow,sans-serif" }}>
            {success}
          </div>
        )}

        <button onClick={handleAuth} disabled={loading}
          style={{ width:"100%", padding:15, background:loading?"#333":"linear-gradient(135deg,"+C.amber+",#FF6B00)", border:"none", borderRadius:12, color:loading?C.gray2:"#000", fontSize:14, fontWeight:700, fontFamily:"Oswald,sans-serif", letterSpacing:2, cursor:loading?"not-allowed":"pointer", marginBottom:14 }}>
          {loading?"PLEASE WAIT...":(mode==="signup"?"CREATE ACCOUNT":"SIGN IN")}
        </button>

        {/* Guest option */}
        <button onClick={onGuest}
          style={{ width:"100%", padding:13, background:"transparent", border:"1px solid "+C.border, borderRadius:12, color:C.gray1, fontSize:12, fontFamily:"Barlow,sans-serif", cursor:"pointer", marginBottom:20 }}>
          Continue as Guest (limited access)
        </button>

        {/* Legal links */}
        <div style={{ textAlign:"center" }}>
          {mode === "signup" && (
            <div style={{ color:C.gray2, fontSize:10, fontFamily:"Barlow,sans-serif", lineHeight:1.8, marginBottom:10 }}>
              By creating an account you agree to our
            </div>
          )}
          <div style={{ display:"flex", justifyContent:"center", gap:16, flexWrap:"wrap" }}>
            <button onClick={()=>setShowTerms(true)} style={{ background:"none", border:"none", color:C.amber, fontSize:11, fontFamily:"Barlow,sans-serif", cursor:"pointer", textDecoration:"underline" }}>Terms of Service</button>
            <button onClick={()=>setShowPrivacy(true)} style={{ background:"none", border:"none", color:C.amber, fontSize:11, fontFamily:"Barlow,sans-serif", cursor:"pointer", textDecoration:"underline" }}>Privacy Policy</button>
            <button onClick={()=>setShowDisclaimer(true)} style={{ background:"none", border:"none", color:C.amber, fontSize:11, fontFamily:"Barlow,sans-serif", cursor:"pointer", textDecoration:"underline" }}>Disclaimer</button>
          </div>
        </div>
      </div>
    </div>
  );
}

